/** Path-based routing for mascot preview vs configure (no react-router). */

export function getMascotBasePath() {
  const path = window.location.pathname.replace(/\/$/, '') || '/'
  if (path.endsWith('/configure')) {
    const base = path.slice(0, -'/configure'.length)
    return base || '/'
  }
  return path
}

export function isConfigurePath() {
  const path = window.location.pathname.replace(/\/$/, '')
  if (path.endsWith('/configure')) return true
  try {
    return new URLSearchParams(window.location.search).get('configure') === '1'
  } catch {
    return false
  }
}

export function getConfigurePath() {
  const base = getMascotBasePath()
  return base === '/' ? '/configure' : `${base}/configure`
}

export function navigateToConfigure({ replace = false } = {}) {
  const next = getConfigurePath()
  const search = window.location.search
  if (replace) {
    window.history.replaceState({ voiceConfigure: true }, '', `${next}${search}`)
  } else {
    window.history.pushState({ voiceConfigure: true }, '', `${next}${search}`)
  }
}

export function navigateToMain({ replace = false } = {}) {
  const next = getMascotBasePath()
  const search = window.location.search
  if (replace) {
    window.history.replaceState({ voiceConfigure: false }, '', `${next}${search}`)
  } else {
    window.history.pushState({ voiceConfigure: false }, '', `${next}${search}`)
  }
}

export function migrateLegacyConfigureQuery() {
  try {
    const params = new URLSearchParams(window.location.search)
    if (params.get('configure') !== '1') return
    if (window.location.pathname.replace(/\/$/, '').endsWith('/configure')) return
    params.delete('configure')
    const search = params.toString()
    const suffix = search ? `?${search}` : ''
    window.history.replaceState({ voiceConfigure: true }, '', `${getConfigurePath()}${suffix}`)
  } catch {
    /* ignore */
  }
}
