import { resolveTextureKey } from './mascotMaterials'
import { kelvinToHex } from './kelvinColor'

const DEFAULT_POOL = 52
const DEFAULT_POOL_INTENSITY = 62
const DEFAULT_KEY_AZIMUTH = 0
const DEFAULT_KEY_KELVIN = 4500
const DEFAULT_KEY_INTENSITY = 28
const DEFAULT_POOL_COLOR = '#f5e6d4'
const DEFAULT_KEY_COLOR = '#ffe8d0'
const DEFAULT_TEXTURE = 'microcement'

function readNum(key, fallback) {
  const saved = localStorage.getItem(key)
  return saved !== null ? Number(saved) : fallback
}

function readStr(key, fallback) {
  const saved = localStorage.getItem(key)
  return saved || fallback
}

/** Main-page slider values — persisted independently from configure drafts. */
export function loadMainUiState() {
  const keyKelvin = readNum('voice-demo-key-kelvin', DEFAULT_KEY_KELVIN)
  return {
    poolSpread: readNum('voice-demo-pool', DEFAULT_POOL),
    poolIntensity: readNum('voice-demo-pool-intensity', DEFAULT_POOL_INTENSITY),
    poolColor: readStr('voice-demo-pool-color', DEFAULT_POOL_COLOR),
    textureKey: resolveTextureKey(localStorage.getItem('voice-demo-texture') || DEFAULT_TEXTURE),
    keyAzimuth: readNum('voice-demo-key-azimuth', DEFAULT_KEY_AZIMUTH),
    keyKelvin,
    keyIntensity: readNum('voice-demo-key-intensity', DEFAULT_KEY_INTENSITY),
    keyColor: readStr('voice-demo-key-color', kelvinToHex(keyKelvin) || DEFAULT_KEY_COLOR)
  }
}
