import React, { Suspense, useRef } from 'react'
import { useFrame } from 'react-three-fiber'
import lerp from 'lerp'
import MascotText from './MascotText'
import {
  sampleAnimation,
  isAnimationComplete,
  ANIMATION_REPEAT_COUNT,
  ANIMATION_LOOP_GAP,
  MASCOT_ANIMATIONS
} from './mascotAnimations'

const POSE_LERP = 0.18
const POSE_BLEND_LERP = 0.05

function lerpPose(a, b, t) {
  return {
    rotX: lerp(a.rotX, b.rotX, t),
    rotY: lerp(a.rotY, b.rotY, t),
    rotZ: lerp(a.rotZ, b.rotZ, t),
    posX: lerp(a.posX, b.posX, t),
    posY: lerp(a.posY, b.posY, t),
    scaleX: lerp(a.scaleX, b.scaleX, t),
    scaleY: lerp(a.scaleY, b.scaleY, t),
    scaleZ: lerp(a.scaleZ, b.scaleZ, t)
  }
}

function animationTime(displayKey, phase, moveElapsed) {
  return displayKey === 'breathe' || displayKey === 'ponder' ? phase : moveElapsed
}

export default function Mascot({
  visualRef,
  poolIntensityRef,
  poolColorRef,
  animationRef,
  stateKeyRef,
  voiceStateToPoseKey,
  textureKey,
  envMapRef,
  keylightRef
}) {
  const outerRef = useRef()
  const pivotRef = useRef()
  const poseRef = useRef({
    rotX: 0,
    rotY: 0,
    rotZ: 0,
    posX: 0,
    posY: 0,
    scaleX: 1,
    scaleY: 1,
    scaleZ: 1
  })
  const baseRotY = useRef(0)
  const breathePhaseRef = useRef(0)
  const lastNowRef = useRef(null)
  const poseBlendRef = useRef({ fromKey: 'breathe', toKey: 'breathe', blend: 1 })

  useFrame(({ clock }) => {
    const visual = visualRef.current
    if (!outerRef.current || !pivotRef.current || !visual) return

    const anim = animationRef?.current
    const now = clock.getElapsedTime()
    const dt = lastNowRef.current == null ? 0 : now - lastNowRef.current
    lastNowRef.current = now
    breathePhaseRef.current += dt * visual.speed

    const stateKey = stateKeyRef?.current ?? 'idle'
    const voicePoseKey = voiceStateToPoseKey?.(stateKey) ?? 'breathe'

    let key = anim?.key ?? 'breathe'
    let displayKey = key
    let moveElapsed = anim?.startTime != null ? now - anim.startTime : 0

    const manualDef = MASCOT_ANIMATIONS[key]
    const manualOneShotActive =
      manualDef && !manualDef.loop && !isAnimationComplete(key, moveElapsed)

    if (!manualOneShotActive) {
      key = voicePoseKey
      displayKey = voicePoseKey
    }

    if (anim?.triggerId != null && anim._lastTrigger !== anim.triggerId) {
      anim._lastTrigger = anim.triggerId
      anim.startTime = now
      anim.pauseUntil = null
      moveElapsed = 0
    }

    if (anim?.pauseUntil != null) {
      if (now < anim.pauseUntil) {
        displayKey = 'breathe'
      } else {
        anim.pauseUntil = null
        anim.startTime = now
        moveElapsed = 0
        displayKey = manualOneShotActive ? key : voicePoseKey
      }
    } else if (manualOneShotActive && isAnimationComplete(key, moveElapsed)) {
      const loopsLeft = (anim.loopsLeft ?? ANIMATION_REPEAT_COUNT) - 1
      if (loopsLeft > 0) {
        anim.loopsLeft = loopsLeft
        anim.pauseUntil = now + ANIMATION_LOOP_GAP
        displayKey = 'breathe'
      } else {
        key = voicePoseKey
        anim.key = voicePoseKey
        anim.loop = true
        anim.loopsLeft = undefined
        anim.pauseUntil = null
        anim.startTime = now
        anim.triggerId = (anim.triggerId ?? 0) + 1
        displayKey = voicePoseKey
        if (animationRef.onComplete) animationRef.onComplete(voicePoseKey)
      }
    }

    const blend = poseBlendRef.current
    if (displayKey !== blend.toKey) {
      blend.fromKey = blend.toKey
      blend.toKey = displayKey
      blend.blend = 0
    }
    blend.blend = lerp(blend.blend, 1, POSE_BLEND_LERP)

    const phase = breathePhaseRef.current
    const poseFrom = sampleAnimation(
      blend.fromKey,
      animationTime(blend.fromKey, phase, moveElapsed)
    )
    const poseTo = sampleAnimation(
      blend.toKey,
      animationTime(blend.toKey, phase, moveElapsed)
    )
    const target = blend.blend < 0.999 ? lerpPose(poseFrom, poseTo, blend.blend) : poseTo

    const p = poseRef.current
    const activeKey = blend.blend < 0.45 ? blend.fromKey : blend.toKey
    const snap =
      activeKey === 'speak'
        ? POSE_LERP * 0.22
        : activeKey === 'listen'
          ? POSE_LERP * 0.72
          : activeKey === 'breathe' || activeKey === 'ponder'
            ? POSE_LERP * 0.55
            : POSE_LERP
    p.rotX = lerp(p.rotX, target.rotX, snap)
    p.rotY = lerp(p.rotY, target.rotY, snap)
    p.rotZ = lerp(p.rotZ, target.rotZ, snap)
    p.posX = lerp(p.posX, target.posX, snap)
    p.posY = lerp(p.posY, target.posY, snap)
    p.scaleX = lerp(p.scaleX, target.scaleX, snap)
    p.scaleY = lerp(p.scaleY, target.scaleY, snap)
    p.scaleZ = lerp(p.scaleZ, target.scaleZ, snap)

    const t = phase
    let breathe = 1
    if (activeKey === 'breathe' || activeKey === 'ponder') {
      breathe = 1 + Math.sin(t * 2.2) * visual.breathe * 1.4
    } else if (activeKey === 'speak') {
      breathe = 1 + Math.sin(t * 4.2) * visual.breathe * 0.75
    } else if (activeKey === 'listen') {
      breathe = 1 + Math.sin(t * 3.2) * visual.breathe * 1.15
    }

    let s = breathe
    if (visual.flashAmount > 0.02) {
      const flashPulse = 0.97 + Math.abs(Math.sin(t * 3.2)) * 0.03
      s *= 1 - (1 - flashPulse) * visual.flashAmount
    }

    const wobble =
      visual.wobble && (activeKey === 'breathe' || activeKey === 'ponder')
        ? Math.sin(t * 2.8) * visual.wobble
        : 0
    baseRotY.current = lerp(baseRotY.current, visual.rotY + Math.sin(t * 0.5) * 0.04, 0.05)

    outerRef.current.position.set(p.posX, p.posY, 0)
    outerRef.current.scale.set(s * p.scaleX, s * p.scaleY, s * p.scaleZ)
    pivotRef.current.rotation.set(p.rotX + wobble, baseRotY.current + p.rotY, p.rotZ)
  })

  return (
    <Suspense fallback={null}>
      <group ref={outerRef} renderOrder={1}>
        <group ref={pivotRef}>
          <MascotText
            visualRef={visualRef}
            poolIntensityRef={poolIntensityRef}
            poolColorRef={poolColorRef}
            textureKey={textureKey}
            envMapRef={envMapRef}
            keylightRef={keylightRef}
            size={5}>
            0
          </MascotText>
        </group>
      </group>
    </Suspense>
  )
}
