import React, { useRef } from 'react'
import { useFrame } from 'react-three-fiber'
import lerp from 'lerp'
import Mascot from './Mascot'
import MascotInspect from './MascotInspect'
import Effects from './Effects'
import SceneBackdrop from './SceneBackdrop'
import SceneEnvironment from './SceneEnvironment'
import VoiceSparkField from './VoiceSparkField'
import { VOICE_STATES } from './voiceStates'
import { blendVoicePreset, lerpToward } from './smoothLerp'

const SCENE_SHIFT_X = -3
const TRANSITION_LERP = 0.06
const SPEAK_BLEND_LERP = 0.08
const SPARK_LERP = 0.06
const FLASH_IN_LERP = 0.1
const FLASH_OUT_LERP = 0.05

function voiceStateToPoseKey(stateKey) {
  if (stateKey === 'speaking') return 'speak'
  if (stateKey === 'listening') return 'listen'
  if (stateKey === 'thinking') return 'ponder'
  return 'breathe'
}

export default function VoiceScene({
  stateKey,
  stateKeyRef,
  mouse,
  poolSpreadRef,
  poolIntensityRef,
  poolColorRef,
  animationRef,
  inspectRef,
  textureKey,
  keylightRef,
  canvasBgRef
}) {
  const visual = useRef({
    ...VOICE_STATES.idle,
    wobble: 0,
    bodyDim: VOICE_STATES.idle.bodyDim,
    bloomThreshold: VOICE_STATES.idle.bloomThreshold,
    sparkWeight: 0,
    flashAmount: 0,
    poolScale: 0.62
  })

  const envRef = useRef(null)
  const keyLightRef = useRef()
  const rimLightRef = useRef()
  const speakWeightRef = useRef(0)

  if (stateKeyRef) stateKeyRef.current = stateKey

  useFrame(() => {
    const currentState = stateKeyRef?.current ?? stateKey
    const inListenSpeakFamily = currentState === 'listening' || currentState === 'speaking'

    let target
    if (inListenSpeakFamily) {
      const speakTarget = currentState === 'speaking' ? 1 : 0
      speakWeightRef.current = lerp(speakWeightRef.current, speakTarget, SPEAK_BLEND_LERP)
      const listenBase = VOICE_STATES.listening
      const speakBase = VOICE_STATES.speaking
      target =
        speakWeightRef.current > 0.02 && speakWeightRef.current < 0.98
          ? blendVoicePreset(listenBase, speakBase, speakWeightRef.current)
          : currentState === 'speaking'
            ? speakBase
            : listenBase
    } else {
      speakWeightRef.current = lerp(speakWeightRef.current, 0, SPEAK_BLEND_LERP)
      target = VOICE_STATES[currentState] || VOICE_STATES.idle
    }

    lerpToward(visual.current, target, TRANSITION_LERP)
    visual.current.poolScale = poolIntensityRef?.current ?? 0.62

    const sparkTarget = target.sparks ? 1 : 0
    visual.current.sparkWeight = lerp(visual.current.sparkWeight ?? 0, sparkTarget, SPARK_LERP)

    if (target.flash) {
      visual.current.flashAmount = lerp(visual.current.flashAmount ?? 0, 1, FLASH_IN_LERP)
    } else {
      visual.current.flashAmount = lerp(visual.current.flashAmount ?? 0, 0, FLASH_OUT_LERP)
    }

    const poolScale = poolIntensityRef?.current ?? 0.62
    const intensity = visual.current.lightIntensity * poolScale
    if (keyLightRef.current) {
      keyLightRef.current.color.set(visual.current.light)
      keyLightRef.current.intensity = lerp(keyLightRef.current.intensity, intensity * 2.2, 0.08)
    }
    if (rimLightRef.current) {
      rimLightRef.current.color.set(visual.current.colorB)
      rimLightRef.current.intensity = lerp(rimLightRef.current.intensity, intensity * 0.45, 0.08)
    }
  })

  return (
    <group position={[SCENE_SHIFT_X, 0, 0]}>
      <SceneEnvironment envRef={envRef} />
      <ambientLight intensity={0.42} />
      <directionalLight ref={keyLightRef} position={[0, 24, 8]} intensity={2.2} />
      <directionalLight ref={rimLightRef} position={[-10, 6, 14]} intensity={0.4} />
      <SceneBackdrop
        visualRef={visual}
        poolSpreadRef={poolSpreadRef}
        poolIntensityRef={poolIntensityRef}
        poolColorRef={poolColorRef}
        canvasBgRef={canvasBgRef}
      />
      <MascotInspect inspectRef={inspectRef}>
        <Mascot
          visualRef={visual}
          poolIntensityRef={poolIntensityRef}
          poolColorRef={poolColorRef}
          animationRef={animationRef}
          stateKeyRef={stateKeyRef}
          voiceStateToPoseKey={voiceStateToPoseKey}
          textureKey={textureKey}
          envMapRef={envRef}
          keylightRef={keylightRef}
        />
      </MascotInspect>
      <VoiceSparkField mouse={mouse} visualRef={visual} />
      <Effects visualRef={visual} />
    </group>
  )
}
