import * as THREE from 'three'
import React, { useState, useRef, useEffect, useCallback } from 'react'
import { Canvas } from 'react-three-fiber'
import VoiceScene from './VoiceScene'
import { VOICE_STATES, STATE_ORDER } from './voiceStates'
import { MASCOT_ANIMATIONS, ANIMATION_ORDER, ANIMATION_REPEAT_COUNT } from './mascotAnimations'
import { TEXTURE_PRESETS, TEXTURE_ORDER, resolveTextureKey } from './mascotMaterials'
import { kelvinToHex, hexToRgb, keylightDirFromAzimuth } from './kelvinColor'
import DockPanel, { DockTab } from './DockPanel'
import { loadMainUiState } from './mainUiState'
import {
  isConfigurePath,
  migrateLegacyConfigureQuery,
  navigateToConfigure,
  navigateToMain
} from './voiceRoutes'
import {
  ZERO_TUNE_STATE_ORDER,
  buildInitialDrafts,
  canvasPctToHex,
  createDefaultSceneConfig,
  draftToUi,
  fetchServerDefaults,
  getApiBase,
  loadLocalSceneConfig,
  normalizeSceneConfig,
  persistServerDefaults,
  saveLocalDefaults,
  saveLocalSceneConfig,
  setApiBase,
  uiToDraft
} from './voiceStateDefaults'
import './voice-demo.css'

const DEFAULT_POOL = 52
const DEFAULT_POOL_INTENSITY = 62
const DEFAULT_KEY_AZIMUTH = 0
const DEFAULT_KEY_KELVIN = 4500
const DEFAULT_KEY_INTENSITY = 28
const DEFAULT_VIEW_YAW = 1
const DEFAULT_VIEW_PITCH = -4
const DEFAULT_POOL_COLOR = '#f5e6d4'
const DEFAULT_KEY_COLOR = '#ffe8d0'
const DEFAULT_CAMERA_Z = 36
const DRAG_SENSITIVITY = 0.009
const PITCH_LIMIT = Math.PI / 2 - 0.12

const radToDeg = r => Math.round((r * 180) / Math.PI)
const degToRad = d => (d * Math.PI) / 180
const normYaw = d => ((d % 360) + 360) % 360

function readCollapsed(key, fallback = false) {
  const saved = localStorage.getItem(`voice-demo-panel-${key}`)
  return saved !== null ? saved === '1' : fallback
}

function applyMainUi(setters, ui) {
  setters.setPoolSpread(ui.poolSpread)
  setters.setPoolIntensity(ui.poolIntensity)
  setters.setPoolColor(ui.poolColor)
  setters.setTextureKey(ui.textureKey)
  setters.setKeyAzimuth(ui.keyAzimuth)
  setters.setKeyKelvin(ui.keyKelvin)
  setters.setKeyColor(ui.keyColor)
  setters.setKeyIntensity(ui.keyIntensity)
}

export default function VoiceDemoApp() {
  const [configMode, setConfigMode] = useState(isConfigurePath)
  const [stateDrafts, setStateDrafts] = useState(buildInitialDrafts)
  const [sceneConfig, setSceneConfig] = useState(loadLocalSceneConfig)
  const [configStatus, setConfigStatus] = useState('')
  const [saving, setSaving] = useState(false)
  const [apiBase, setApiBaseState] = useState(getApiBase)
  const [stateKey, setStateKey] = useState('idle')
  const [inspectEnabled, setInspectEnabled] = useState(true)
  const [inspectView, setInspectView] = useState({
    yaw: DEFAULT_VIEW_YAW,
    pitch: DEFAULT_VIEW_PITCH
  })
  const [panels, setPanels] = useState({
    texture: readCollapsed('texture'),
    keylight: readCollapsed('keylight'),
    inspect: readCollapsed('inspect'),
    anim: readCollapsed('anim')
  })
  const [textureKey, setTextureKey] = useState(() => {
    const saved = localStorage.getItem('voice-demo-texture')
    return saved ? resolveTextureKey(saved) : 'microcement'
  })
  const [isDragging, setIsDragging] = useState(false)

  useEffect(() => {
    if (configMode) return
    localStorage.setItem('voice-demo-texture', textureKey)
  }, [textureKey, configMode])

  const [poolSpread, setPoolSpread] = useState(() => {
    const saved = localStorage.getItem('voice-demo-pool')
    return saved !== null ? Number(saved) : DEFAULT_POOL
  })
  const [poolIntensity, setPoolIntensity] = useState(() => {
    const saved = localStorage.getItem('voice-demo-pool-intensity')
    return saved !== null ? Number(saved) : DEFAULT_POOL_INTENSITY
  })
  const [keyAzimuth, setKeyAzimuth] = useState(() => {
    const saved = localStorage.getItem('voice-demo-key-azimuth')
    return saved !== null ? Number(saved) : DEFAULT_KEY_AZIMUTH
  })
  const [keyKelvin, setKeyKelvin] = useState(() => {
    const saved = localStorage.getItem('voice-demo-key-kelvin')
    return saved !== null ? Number(saved) : DEFAULT_KEY_KELVIN
  })
  const [keyIntensity, setKeyIntensity] = useState(() => {
    const saved = localStorage.getItem('voice-demo-key-intensity')
    return saved !== null ? Number(saved) : DEFAULT_KEY_INTENSITY
  })
  const [poolColor, setPoolColor] = useState(() => {
    const saved = localStorage.getItem('voice-demo-pool-color')
    return saved || DEFAULT_POOL_COLOR
  })
  const [keyColor, setKeyColor] = useState(() => {
    const saved = localStorage.getItem('voice-demo-key-color')
    return saved || DEFAULT_KEY_COLOR
  })

  const mouse = useRef([0, 0])
  const poolSpreadRef = useRef(DEFAULT_POOL / 100)
  const poolIntensityRef = useRef(DEFAULT_POOL_INTENSITY / 100)
  const poolColorRef = useRef(new THREE.Color(DEFAULT_POOL_COLOR))
  const canvasBgRef = useRef(new THREE.Color(canvasPctToHex(loadLocalSceneConfig().backgroundCanvasPct)))
  const keylightRef = useRef({
    azimuth: DEFAULT_KEY_AZIMUTH,
    kelvin: DEFAULT_KEY_KELVIN,
    intensity: DEFAULT_KEY_INTENSITY / 100,
    dir: keylightDirFromAzimuth(DEFAULT_KEY_AZIMUTH),
    color: hexToRgb(DEFAULT_KEY_COLOR)
  })
  const stableSceneConfig = sceneConfig || createDefaultSceneConfig()
  const canvasBg = canvasPctToHex(stableSceneConfig.backgroundCanvasPct)

  const snapshotUiToDraft = useCallback(() => {
    return uiToDraft({
      poolSpread,
      poolIntensity,
      poolColor,
      textureKey,
      keyAzimuth,
      keyKelvin,
      keyIntensity
    })
  }, [poolSpread, poolIntensity, poolColor, textureKey, keyAzimuth, keyKelvin, keyIntensity])

  const applyDraftToUi = useCallback(draft => {
    const ui = draftToUi(draft)
    setPoolSpread(ui.poolSpread)
    setPoolIntensity(ui.poolIntensity)
    setPoolColor(ui.poolColor)
    setTextureKey(resolveTextureKey(ui.textureKey))
    setKeyAzimuth(ui.keyAzimuth)
    setKeyKelvin(ui.keyKelvin)
    setKeyColor(kelvinToHex(ui.keyKelvin))
    setKeyIntensity(ui.keyIntensity)
  }, [])

  const persistCurrentDraft = useCallback(() => {
    const next = snapshotUiToDraft()
    setStateDrafts(prev => ({ ...prev, [stateKey]: next }))
    return next
  }, [snapshotUiToDraft, stateKey])

  const switchVoiceState = useCallback(
    nextKey => {
      if (configMode) {
        setStateDrafts(prev => {
          const updated = { ...prev, [stateKey]: snapshotUiToDraft() }
          const draft = updated[nextKey]
          if (draft) applyDraftToUi(draft)
          return updated
        })
      }
      setStateKey(nextKey)
    },
    [configMode, stateKey, snapshotUiToDraft, applyDraftToUi]
  )

  const bootstrapConfigure = useCallback(() => {
    const drafts = buildInitialDrafts()
    setStateDrafts(drafts)
    setSceneConfig(loadLocalSceneConfig())
    setConfigMode(true)
    const draft = drafts[stateKey]
    if (draft) applyDraftToUi(draft)
  }, [stateKey, applyDraftToUi])

  const restoreMainPage = useCallback(() => {
    setConfigMode(false)
    setConfigStatus('')
    applyMainUi(
      {
        setPoolSpread,
        setPoolIntensity,
        setPoolColor,
        setTextureKey,
        setKeyAzimuth,
        setKeyKelvin,
        setKeyColor,
        setKeyIntensity
      },
      loadMainUiState()
    )
    setSceneConfig(loadLocalSceneConfig())
  }, [])

  useEffect(() => {
    migrateLegacyConfigureQuery()
    if (isConfigurePath()) {
      bootstrapConfigure()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  useEffect(() => {
    const onPopState = () => {
      if (isConfigurePath()) {
        bootstrapConfigure()
      } else {
        restoreMainPage()
      }
    }
    window.addEventListener('popstate', onPopState)
    return () => window.removeEventListener('popstate', onPopState)
  }, [bootstrapConfigure, restoreMainPage])

  useEffect(() => {
    if (!configMode) return
    const draft = stateDrafts[stateKey]
    if (draft) applyDraftToUi(draft)
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [configMode])

  useEffect(() => {
    let cancelled = false
    ;(async () => {
      try {
        const server = await fetchServerDefaults()
        if (cancelled) return
        if (Object.keys(server).length) {
          setStateDrafts(prev => {
            const next = { ...prev }
            for (const key of ZERO_TUNE_STATE_ORDER) {
              if (server[key]) next[key] = server[key]
            }
            return next
          })
          saveLocalDefaults(server)
        }
        const scene = loadLocalSceneConfig()
        setSceneConfig(scene)
        if (configMode) {
          const draft = server[stateKey] || stateDrafts[stateKey]
          if (draft) applyDraftToUi(draft)
        }
      } catch {
        /* offline — local only */
      }
    })()
    return () => {
      cancelled = true
    }
  }, [apiBase])

  useEffect(() => {
    document.documentElement.style.setProperty('--voice-demo-canvas-bg', canvasBg)
    return () => {
      document.documentElement.style.removeProperty('--voice-demo-canvas-bg')
    }
  }, [canvasBg])

  const persistDraftToMainStorage = useCallback(draft => {
    const ui = draftToUi(draft)
    localStorage.setItem('voice-demo-pool', String(ui.poolSpread))
    localStorage.setItem('voice-demo-pool-intensity', String(ui.poolIntensity))
    localStorage.setItem('voice-demo-pool-color', ui.poolColor)
    localStorage.setItem('voice-demo-texture', ui.textureKey)
    localStorage.setItem('voice-demo-key-azimuth', String(ui.keyAzimuth))
    localStorage.setItem('voice-demo-key-kelvin', String(ui.keyKelvin))
    localStorage.setItem('voice-demo-key-intensity', String(ui.keyIntensity))
    localStorage.setItem('voice-demo-key-color', keyColor)
  }, [keyColor])

  const saveCurrentState = () => {
    const nextDrafts = { ...stateDrafts, [stateKey]: persistCurrentDraft() }
    setStateDrafts(nextDrafts)
    saveLocalDefaults(nextDrafts)
    persistDraftToMainStorage(nextDrafts[stateKey])
    setConfigStatus(`Saved ${VOICE_STATES[stateKey].label} locally.`)
  }

  const saveAllAndSync = async () => {
    setSaving(true)
    setConfigStatus('')
    const nextDrafts = { ...stateDrafts, [stateKey]: persistCurrentDraft() }
    setStateDrafts(nextDrafts)
    try {
      saveLocalDefaults(nextDrafts)
      saveLocalSceneConfig(sceneConfig)
      setApiBase(apiBase)
      persistDraftToMainStorage(nextDrafts[stateKey])
      await persistServerDefaults(nextDrafts, sceneConfig)
      setConfigStatus('Saved all states and synced to receptionist demo.')
    } catch (error) {
      saveLocalDefaults(nextDrafts)
      saveLocalSceneConfig(sceneConfig)
      persistDraftToMainStorage(nextDrafts[stateKey])
      setConfigStatus(`Saved locally. Server sync failed: ${error.message}`)
    } finally {
      setSaving(false)
    }
  }

  const enterConfigMode = () => {
    navigateToConfigure()
    bootstrapConfigure()
    setConfigStatus('Configure each voice state, then save all to sync with the receptionist demo.')
  }

  const exitConfigMode = () => {
    navigateToMain()
    restoreMainPage()
  }

  const updateBackgroundCanvasPct = useCallback(
    nextPct => {
      setSceneConfig(prev => {
        const next = normalizeSceneConfig({
          ...(prev && typeof prev === 'object' ? prev : {}),
          backgroundCanvasPct: nextPct
        })
        if (!configMode) saveLocalSceneConfig(next)
        return next
      })
    },
    [configMode]
  )

  const animationRef = useRef({ key: 'breathe', loop: true, startTime: 0, triggerId: 0 })
  const stateKeyRef = useRef(stateKey)
  stateKeyRef.current = stateKey
  const [animKey, setAnimKey] = useState('breathe')
  const triggerIdRef = useRef(0)
  const inspectRef = useRef({
    enabled: true,
    rotX: degToRad(DEFAULT_VIEW_PITCH),
    rotY: degToRad(DEFAULT_VIEW_YAW)
  })
  const dragRef = useRef(null)

  const togglePanel = useCallback(key => {
    setPanels(prev => {
      const next = { ...prev, [key]: !prev[key] }
      localStorage.setItem(`voice-demo-panel-${key}`, next[key] ? '1' : '0')
      return next
    })
  }, [])

  const syncInspectView = useCallback(() => {
    setInspectView({
      yaw: normYaw(radToDeg(inspectRef.current.rotY)),
      pitch: radToDeg(inspectRef.current.rotX)
    })
  }, [])

  const setInspectAngles = useCallback((yawDeg, pitchDeg) => {
    const pitch = Math.max(-75, Math.min(75, pitchDeg))
    inspectRef.current.rotY = degToRad(yawDeg)
    inspectRef.current.rotX = degToRad(pitch)
    setInspectView({ yaw: normYaw(yawDeg), pitch })
  }, [])

  const resetInspect = useCallback(() => {
    inspectRef.current.rotX = degToRad(DEFAULT_VIEW_PITCH)
    inspectRef.current.rotY = degToRad(DEFAULT_VIEW_YAW)
    setInspectView({ yaw: DEFAULT_VIEW_YAW, pitch: DEFAULT_VIEW_PITCH })
  }, [])

  inspectRef.current.enabled = inspectEnabled

  const playAnimation = useCallback(key => {
    const def = MASCOT_ANIMATIONS[key]
    if (!def) return
    triggerIdRef.current += 1
    animationRef.current = {
      key,
      loop: def.loop,
      loopsLeft: def.loop ? undefined : ANIMATION_REPEAT_COUNT,
      pauseUntil: null,
      startTime: null,
      triggerId: triggerIdRef.current,
      _lastTrigger: null,
      onComplete: k => setAnimKey(k)
    }
    setAnimKey(key)
  }, [])

  poolSpreadRef.current = poolSpread / 100
  poolIntensityRef.current = poolIntensity / 100
  poolColorRef.current.set(poolColor)
  keylightRef.current.azimuth = keyAzimuth
  keylightRef.current.kelvin = keyKelvin
  keylightRef.current.intensity = keyIntensity / 100
  keylightDirFromAzimuth(keyAzimuth, keylightRef.current.dir)
  hexToRgb(keyColor, keylightRef.current.color)

  useEffect(() => {
    if (configMode) return
    localStorage.setItem('voice-demo-pool', String(poolSpread))
  }, [poolSpread, configMode])

  useEffect(() => {
    poolIntensityRef.current = poolIntensity / 100
  }, [poolIntensity])

  useEffect(() => {
    if (configMode) return
    localStorage.setItem('voice-demo-pool-intensity', String(poolIntensity))
  }, [poolIntensity, configMode])

  useEffect(() => {
    if (configMode) return
    localStorage.setItem('voice-demo-key-azimuth', String(keyAzimuth))
  }, [keyAzimuth, configMode])

  useEffect(() => {
    if (configMode) return
    localStorage.setItem('voice-demo-key-kelvin', String(keyKelvin))
  }, [keyKelvin, configMode])

  useEffect(() => {
    if (configMode) return
    localStorage.setItem('voice-demo-key-intensity', String(keyIntensity))
  }, [keyIntensity, configMode])

  useEffect(() => {
    if (configMode) return
    localStorage.setItem('voice-demo-pool-color', poolColor)
  }, [poolColor, configMode])

  useEffect(() => {
    if (configMode) return
    localStorage.setItem('voice-demo-key-color', keyColor)
  }, [keyColor, configMode])

  canvasBgRef.current.set(canvasBg)

  const onPointerDown = useCallback(
    e => {
      if (!inspectEnabled || e.button !== 0) return
      e.target.setPointerCapture(e.pointerId)
      dragRef.current = {
        x: e.clientX,
        y: e.clientY,
        rotX: inspectRef.current.rotX,
        rotY: inspectRef.current.rotY
      }
      setIsDragging(true)
    },
    [inspectEnabled]
  )

  const onPointerMove = useCallback(
    e => {
      if (!dragRef.current) return
      const dx = e.clientX - dragRef.current.x
      const dy = e.clientY - dragRef.current.y
      inspectRef.current.rotY = dragRef.current.rotY + dx * DRAG_SENSITIVITY
      inspectRef.current.rotX = Math.max(
        -PITCH_LIMIT,
        Math.min(PITCH_LIMIT, dragRef.current.rotX + dy * DRAG_SENSITIVITY)
      )
      syncInspectView()
    },
    [syncInspectView]
  )

  const onPointerUp = useCallback(e => {
    if (!dragRef.current) return
    dragRef.current = null
    setIsDragging(false)
    try {
      e.target.releasePointerCapture(e.pointerId)
    } catch (_) {
      /* already released */
    }
  }, [])

  return (
    <div className={`voice-demo-viewport${configMode ? ' is-config-mode' : ''}`}>
      <div className="voice-demo__scene">
        <div className="voice-demo__base" style={{ background: canvasBg }} />
        <div
          className="voice-demo__footer-shield"
          style={{
            background: `linear-gradient(to top, ${canvasBg} 0%, ${canvasBg}f0 35%, ${canvasBg}80 65%, transparent 100%)`
          }}
        />

        <Canvas
          className={`voice-demo__canvas${inspectEnabled ? ' is-inspect' : ''}${isDragging ? ' is-dragging' : ''}`}
          pixelRatio={Math.min(3, window.devicePixelRatio || 1)}
          gl={{ alpha: true, antialias: true, powerPreference: 'high-performance' }}
          camera={{ fov: 82, position: [0, 0, DEFAULT_CAMERA_Z] }}
          onPointerDown={onPointerDown}
          onPointerMove={onPointerMove}
          onPointerUp={onPointerUp}
          onPointerLeave={onPointerUp}
          onCreated={({ gl }) => {
            gl.toneMapping = THREE.NoToneMapping
            gl.toneMappingExposure = 1.0
            gl.setClearColor(0x000000, 0)
          }}>
          <VoiceScene
            stateKey={stateKey}
            stateKeyRef={stateKeyRef}
            mouse={mouse}
            poolSpreadRef={poolSpreadRef}
            poolIntensityRef={poolIntensityRef}
            poolColorRef={poolColorRef}
            animationRef={animationRef}
            inspectRef={inspectRef}
            textureKey={textureKey}
            keylightRef={keylightRef}
            canvasBgRef={canvasBgRef}
          />
        </Canvas>
      </div>

      <div className="voice-demo__chrome">
      <header className="voice-demo__header">
        <div className="voice-demo__brand">Voice Concierge</div>
        <div className="voice-demo__meta">
          {configMode ? 'Receptionist demo configuration' : 'Mascot state preview'}
        </div>
        <div className="voice-demo__header-actions">
      {configMode ? (
            <button type="button" className="voice-demo__config-btn" onClick={exitConfigMode}>
              Exit configure
            </button>
          ) : (
            <a
              className="voice-demo__config-btn voice-demo__config-btn--primary"
              href="configure"
              onClick={e => {
                if (!e.metaKey && !e.ctrlKey && e.button === 0) {
                  e.preventDefault()
                  enterConfigMode()
                }
              }}>
              Configure Receptionist Demo
            </a>
          )}
        </div>
      </header>

      <nav className="voice-demo__nav" aria-label="Voice states">
        {STATE_ORDER.map(key => (
          <button
            key={key}
            type="button"
            className={`voice-demo__nav-btn${stateKey === key ? ' is-active' : ''}`}
            onClick={() => switchVoiceState(key)}>
            {VOICE_STATES[key].label}
          </button>
        ))}
      </nav>

      <div className="voice-demo__dock-tabs voice-demo__dock-tabs--left">
        {panels.texture ? (
          <DockTab title="Surface" side="left" onClick={() => togglePanel('texture')} />
        ) : null}
        {panels.keylight ? (
          <DockTab title="Key Light" side="left" onClick={() => togglePanel('keylight')} />
        ) : null}
        {panels.inspect ? (
          <DockTab title="Orbit" side="left" onClick={() => togglePanel('inspect')} />
        ) : null}
      </div>

      <div className="voice-demo__dock-tabs voice-demo__dock-tabs--right">
        {!configMode && panels.anim ? (
          <DockTab title="Moves" side="right" onClick={() => togglePanel('anim')} />
        ) : null}
      </div>

      <div className="voice-demo__left-rail">
        <div className="voice-demo__left-stack">
          {configMode ? (
            <DockPanel
              title="Receptionist Config"
              subtitle="Save to sync with the live demo"
              className="voice-demo__dock-panel--config">
              <label className="voice-demo__config-api">
                <span>Receptionist API</span>
                <input
                  type="url"
                  value={apiBase}
                  onChange={e => setApiBaseState(e.target.value)}
                  placeholder="http://127.0.0.1:4173"
                />
              </label>
              <div className="voice-demo__config-actions">
                <button type="button" className="voice-demo__config-btn" onClick={saveCurrentState}>
                  Save {VOICE_STATES[stateKey].label}
                </button>
                <button
                  type="button"
                  className="voice-demo__config-btn voice-demo__config-btn--primary"
                  disabled={saving}
                  onClick={saveAllAndSync}>
                  {saving ? 'Saving…' : 'Save all & sync'}
                </button>
              </div>
              {configStatus ? <p className="voice-demo__config-status">{configStatus}</p> : null}
            </DockPanel>
          ) : null}

          {!panels.texture ? (
            <DockPanel
              title="Surface Finish"
              subtitle={TEXTURE_PRESETS[textureKey]?.hint}
              onMinimize={() => togglePanel('texture')}>
              <div className="voice-demo__texture-grid">
                {TEXTURE_ORDER.map(key => (
                  <button
                    key={key}
                    type="button"
                    className={`voice-demo__texture-btn${textureKey === key ? ' is-active' : ''}`}
                    onClick={() => setTextureKey(key)}>
                    {TEXTURE_PRESETS[key].label}
                  </button>
                ))}
              </div>
            </DockPanel>
          ) : null}

          {!panels.keylight ? (
            <DockPanel
              title="Front Key Light"
              subtitle="PBR finishes only — sweeps the front equator"
              onMinimize={() => togglePanel('keylight')}
              className="voice-demo__dock-panel--keylight">
            <label className="voice-demo__glow-control voice-demo__glow-control--panel">
              <span className="voice-demo__glow-label">Sweep</span>
              <input
                type="range"
                className="voice-demo__glow-slider voice-demo__glow-slider--wide"
                min={-90}
                max={90}
                value={keyAzimuth}
                onChange={e => setKeyAzimuth(Number(e.target.value))}
                aria-valuenow={keyAzimuth}
              />
              <span className="voice-demo__glow-value">{keyAzimuth}°</span>
            </label>
            <div className="voice-demo__keylight-axis">
              <span>Left</span>
              <span>Centre</span>
              <span>Right</span>
            </div>

            <div className="voice-demo__color-field">
              <span className="voice-demo__color-label">RGB colour</span>
              <input
                type="color"
                className="voice-demo__color-input"
                value={keyColor}
                onChange={e => setKeyColor(e.target.value)}
                aria-label="Key light RGB colour"
              />
              <span className="voice-demo__color-hex">{keyColor}</span>
            </div>

            <label className="voice-demo__glow-control voice-demo__glow-control--panel">
              <span className="voice-demo__glow-label">Intensity</span>
              <input
                type="range"
                className="voice-demo__glow-slider voice-demo__glow-slider--wide"
                min={0}
                max={100}
                value={keyIntensity}
                onChange={e => setKeyIntensity(Number(e.target.value))}
                aria-valuenow={keyIntensity}
              />
              <span className="voice-demo__glow-value">{keyIntensity}%</span>
            </label>
            </DockPanel>
          ) : null}
        </div>

        <div className="voice-demo__controls">
          <label className="voice-demo__glow-control voice-demo__glow-control--panel">
            <span className="voice-demo__glow-label">Canvas background</span>
            <input
              type="range"
              className="voice-demo__glow-slider voice-demo__glow-slider--wide"
              min={0}
              max={100}
              value={stableSceneConfig.backgroundCanvasPct}
              onChange={e => updateBackgroundCanvasPct(Number(e.target.value))}
              aria-valuenow={stableSceneConfig.backgroundCanvasPct}
            />
            <span className="voice-demo__glow-value">{canvasBg}</span>
          </label>

          {!panels.inspect ? (
            <DockPanel
              title="Orbit Inspect"
              subtitle={inspectEnabled ? 'Drag the mascot to rotate 360°' : 'Enable to orbit the object'}
              onMinimize={() => togglePanel('inspect')}
              className="voice-demo__dock-panel--inspect"
              actions={
                <button
                  type="button"
                  className={`voice-demo__inspect-toggle${inspectEnabled ? ' is-on' : ''}`}
                  onClick={() => setInspectEnabled(v => !v)}
                  aria-pressed={inspectEnabled}>
                  {inspectEnabled ? 'On' : 'Off'}
                </button>
              }>
              <label className="voice-demo__glow-control voice-demo__glow-control--compact">
                <span className="voice-demo__glow-label">Yaw</span>
                <input
                  type="range"
                  className="voice-demo__glow-slider voice-demo__glow-slider--wide"
                  min={0}
                  max={360}
                  value={inspectView.yaw}
                  disabled={!inspectEnabled}
                  onChange={e => setInspectAngles(Number(e.target.value), inspectView.pitch)}
                  aria-valuenow={inspectView.yaw}
                />
                <span className="voice-demo__glow-value">{inspectView.yaw}°</span>
              </label>
              <label className="voice-demo__glow-control voice-demo__glow-control--compact">
                <span className="voice-demo__glow-label">Pitch</span>
                <input
                  type="range"
                  className="voice-demo__glow-slider voice-demo__glow-slider--wide"
                  min={-75}
                  max={75}
                  value={inspectView.pitch}
                  disabled={!inspectEnabled}
                  onChange={e => setInspectAngles(inspectView.yaw, Number(e.target.value))}
                  aria-valuenow={inspectView.pitch}
                />
                <span className="voice-demo__glow-value">{inspectView.pitch}°</span>
              </label>
              <button
                type="button"
                className="voice-demo__inspect-reset"
                disabled={!inspectEnabled}
                onClick={resetInspect}>
                Reset view
              </button>
            </DockPanel>
          ) : null}

          <div className="voice-demo__pool-color">
            <div className="voice-demo__color-field voice-demo__color-field--pool">
              <span className="voice-demo__color-label">Pool colour</span>
              <input
                type="color"
                className="voice-demo__color-input"
                value={poolColor}
                onChange={e => setPoolColor(e.target.value)}
                aria-label="Pool light RGB colour"
              />
              <span className="voice-demo__color-hex">{poolColor}</span>
            </div>
          </div>

          <label className="voice-demo__glow-control">
            <span className="voice-demo__glow-label">Pool width</span>
            <input
              type="range"
              className="voice-demo__glow-slider voice-demo__glow-slider--wide"
              min={20}
              max={100}
              value={poolSpread}
              onChange={e => setPoolSpread(Number(e.target.value))}
              aria-valuenow={poolSpread}
            />
            <span className="voice-demo__glow-value">{poolSpread}%</span>
          </label>

          <label className="voice-demo__glow-control">
            <span className="voice-demo__glow-label">Pool light</span>
            <input
              type="range"
              className="voice-demo__glow-slider voice-demo__glow-slider--wide"
              min={0}
              max={100}
              value={poolIntensity}
              onChange={e => {
                poolIntensityRef.current = Number(e.target.value) / 100
                setPoolIntensity(Number(e.target.value))
              }}
              aria-valuenow={poolIntensity}
            />
            <span className="voice-demo__glow-value">{poolIntensity}%</span>
          </label>
        </div>
      </div>

      <div className="voice-demo__right-rail">
        {!configMode && !panels.anim ? (
          <DockPanel
            title="Character Moves"
            subtitle={MASCOT_ANIMATIONS[animKey]?.hint}
            onMinimize={() => togglePanel('anim')}
            className="voice-demo__dock-panel--anim">
            <div className="voice-demo__anim-grid">
              {ANIMATION_ORDER.map(key => (
                <button
                  key={key}
                  type="button"
                  className={`voice-demo__anim-btn${animKey === key ? ' is-active' : ''}`}
                  onClick={() => playAnimation(key)}>
                  {MASCOT_ANIMATIONS[key].label}
                </button>
              ))}
            </div>
          </DockPanel>
        ) : null}
      </div>

      <div className="voice-demo__debug">
        <span>STATE: {stateKey}</span>
        <span>MOVE: {MASCOT_ANIMATIONS[animKey]?.label}</span>
        <span>SURF: {TEXTURE_PRESETS[textureKey]?.label}</span>
        <span>YAW: {inspectView.yaw}°</span>
        <span>PITCH: {inspectView.pitch}°</span>
        <span>POOL: {(poolIntensity / 100).toFixed(2)}</span>
        <span>KEY: {keyAzimuth}° / {keyColor} / {(keyIntensity / 100).toFixed(2)}</span>
      </div>
      </div>
    </div>
  )
}
